(window.webpackJsonp=window.webpackJsonp||[]).push([[192],{819:function(n,e){n.exports="\x3c!-- \ntitle: 34-Flask\nsort: \n--\x3e \n# Flask入门\n\n## HelloWorld\n\n```python\nfrom flask import Flask\n\nserver = Flask(__name__)\n\n@server.route('/')\ndef index():\n    return '<h2>Flask Running...</h2>'\n \nserver.run('127.0.0.1',port=8080)\n```\n\n## 上传文件\n\n```python\n@server.route('/upload', methods=['GET', 'POST'])\ndef upload():\n    keygen = request.form.get('keygen')\n    fname = request.files['upload']\n    if keygen == 'passwd' and 'fname':\n        t = time.strftime('%Y-%m-%d_%H-%M-%S_')\n        name = t + fname.filename\n        fname.save('./upload/' + name)\n        return '<h2>Upload Success!</h2>'\n    else:\n        return '<h2>Please Select File!</h2>'\n```\n\n## POST\n\n```python\n# Get参数获取\nrequest.args.get('mess')\nrequest.args['mess']\n# form-data获取\nrequest.form.get('mess')\n# paload-json获取\nrequest.json['mess']\n```\n\n## 跨域请求\n\n```python\nfrom flask_cors import *\nCORS(app, supports_credentials=True)\n```\n\n## Json\n\n```python\nfrom flask import jsonify\n@server.route('/')\ndef index():\n    return jsonify({\n    'code': 200,\n    'msg': '成功'     \n    })\n```\n\n"}}]);